        "sql": [
          "* if user ask about regulation code use table dim_regulation\r\n",
          "* when user ask  dim_position and ask about date use open_occured column\r\n",
          "* when its need to sum pnl use dim_positionnl table\r\n",
          "* when ask about crypto filter on dim_instrument table where InstrumentType='Crypto Currencies'\r\n",
          "* when ask about regulation 'UAE' use dim_regulation as regulation 'FSRA'\r\n",
          "* when ask about position  equity then use amount+positionpnl\r\n",
          "* when ask abot balance equity use liabilities"
        ]
      },
      {
        "id": "01eec4ec1cd51a889b79250f53e571ef",
        "question": [
          "show me all UAE regulations as of yesterday and their position equity and balance equity in the last 7 days break down by DateID"
        ],
        "sql": [
          "SELECT dc.CID\r\n",
          "      ,dc.RegulationID\r\n",
          "      ,COALESCE(vlb.Date, pnl.Date) AS Date\r\n",
          "      ,MAX(pnl.PositionEquity) AS PositionEquity\r\n",
          "      ,MAX(vlb.BalanceEquity) AS BalanceEquity\r\n",
          "FROM main.dwh.dim_customer dc\r\n",
          "LEFT JOIN(\r\n",
          "SELECT pnl.CID\r\n",
          "      ,pnl.Date\r\n",
          "      ,SUM(ISNULL(pnl.Amount,0) + ISNULL(pnl.PositionPnL,0)) AS PositionEquity\r\n",
          "FROM main.bi_db.gold_bi_db_bi_db_positionpnl pnl\r\n",
          "where pnl.Date >= Current_Date()-3\r\n",
          "group by pnl.CID, pnl.Date) pnl \r\n",
          "on dc.CID = pnl.CID\r\n",
          "LEFT JOIN(\r\n",
          "SELECT vlb.CID\r\n",
          "      ,vlb.Date\r\n",
          "      ,ISNULL(vlb.Liabilities,0) AS BalanceEquity\r\n",
          "FROM main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities vlb\r\n",
          "where vlb.Date >= Current_Date()-3) vlb \r\n",
          "on dc.CID = vlb.CID\r\n",
          "WHERE dc.RegulationID = 11 \r\n",
          "AND dc.IsValidCustomer = 1\r\n",
          "group by dc.CID\r\n",
          "      ,dc.RegulationID"
        ]
      }
    ]
